import{_ as o,c as e,o as t,a1 as r}from"./chunks/framework.DDNAyvCW.js";const l="/assets/host_conn.D9LgeRwL.png",u=JSON.parse('{"title":"连接到主机","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/connect.md","filePath":"docs/hosts/connect.md"}'),s={name:"docs/hosts/connect.md"};function i(n,a,h,d,c,p){return t(),e("div",null,a[0]||(a[0]=[r('<h1 id="连接到主机" tabindex="-1">连接到主机 <a class="header-anchor" href="#连接到主机" aria-label="Permalink to &quot;连接到主机&quot;">​</a></h1><p>将主机添加到 Chaterm 后，您只需单击即可打开到该主机的 SSH 会话。</p><p><img src="'+l+'" alt=""></p><h2 id="如何连接" tabindex="-1">如何连接 <a class="header-anchor" href="#如何连接" aria-label="Permalink to &quot;如何连接&quot;">​</a></h2><ol><li>从左侧边栏打开 <strong>主机管理</strong> 页面，或在工作区中找到目标主机。</li><li>在主机列表中点击目标主机条目。</li><li>Chaterm 建立 SSH 连接并为该会话打开终端窗口。</li></ol><h2 id="连接失败排查" tabindex="-1">连接失败排查 <a class="header-anchor" href="#连接失败排查" aria-label="Permalink to &quot;连接失败排查&quot;">​</a></h2><p>如果连接失败或意外断开，请尝试以下步骤：</p><ol><li><strong>验证网络可达性</strong> -- 确保您的机器可以到达目标主机。尝试从本地终端 ping 主机 IP 地址。</li><li><strong>检查凭据</strong> -- 确认用户名、密码或 SSH 密钥正确。您可以通过编辑主机条目来更新凭据（详见 <a href="/docs/hosts/edit-clone-delete">编辑、克隆与删除</a>）。</li><li><strong>确认 SSH 服务正在运行</strong> -- 确保目标主机上的 SSH 守护进程（如 <code>sshd</code>）正在运行并监听配置的端口。</li><li><strong>检查端口号</strong> -- SSH 默认端口为 <code>22</code>。如果服务器使用不同端口，请确保 Chaterm 中的主机条目匹配。</li><li><strong>检查防火墙规则</strong> -- 服务器或网络上的防火墙可能阻止了 SSH 端口。验证 SSH 端口的入站流量是否被允许。</li><li><strong>检查 SSH 代理</strong> -- 如果配置了 SSH 代理，请确保代理服务器本身可达且配置正确。</li><li><strong>轮换或重新导入密钥</strong> -- 如果使用密钥认证且密钥最近在服务器上更改过，请在 <a href="/docs/manage/keys/">密钥管理</a> 中更新或重新导入密钥。</li></ol><h2 id="终端功能" tabindex="-1">终端功能 <a class="header-anchor" href="#终端功能" aria-label="Permalink to &quot;终端功能&quot;">​</a></h2><p>连接后，终端窗口提供多种提高效率的功能：</p><h3 id="多标签页" tabindex="-1">多标签页 <a class="header-anchor" href="#多标签页" aria-label="Permalink to &quot;多标签页&quot;">​</a></h3><p>同时打开多台主机的连接。每个连接在终端区域顶部以独立标签页打开。点击标签页可在会话间切换，也可使用快捷键快速切换。</p><h3 id="分屏" tabindex="-1">分屏 <a class="header-anchor" href="#分屏" aria-label="Permalink to &quot;分屏&quot;">​</a></h3><p>水平或垂直分割终端区域，并排查看多个会话。当您需要比较不同服务器的输出或在一台主机上运行命令同时监控另一台时非常有用。</p><h3 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h3><p>右键点击终端标签页可访问快捷操作：</p><ul><li><strong>关闭</strong> 当前标签页。</li><li><strong>重命名</strong> 标签页以便于识别。</li><li><strong>克隆</strong> 会话，在新标签页中打开重复连接。</li><li>其他取决于上下文的操作。</li></ul><h3 id="终端搜索" tabindex="-1">终端搜索 <a class="header-anchor" href="#终端搜索" aria-label="Permalink to &quot;终端搜索&quot;">​</a></h3><p>使用快捷键或菜单打开终端内的搜索面板。您可以在终端输出历史中搜索特定命令、日志条目或文本。</p><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/docs/terminal/operations/">终端操作</a> -- 了解高级终端功能，如代码片段、自动补全和 AI 辅助命令。</li><li><a href="/docs/hosts/add-personal">添加个人主机</a> -- 将新服务器添加到主机列表。</li><li><a href="/docs/hosts/add-bastion">添加堡垒机</a> -- 添加企业堡垒机/跳板服务器。</li><li><a href="/docs/hosts/add-router">添加路由器</a> -- 添加网络设备。</li><li><a href="/docs/manage/keys/">密钥管理</a> -- 管理用于认证的 SSH 密钥。</li></ul>',21)]))}const S=o(s,[["render",i]]);export{u as __pageData,S as default};
